module clock_divider (
    input wire clk,
    input wire rst,
    output reg clk_out
);
    reg [1:0] countdown;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            countdown <= 0;
            clk_out <= 0;
        end else begin
            countdown <= countdown + 1;
            if (countdown == 3) begin
                clk_out <= ~clk_out;
                countdown <= 0;
            end
        end
    end
endmodule
